// frontend/src/components/Navbar/Navbar.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Navbar = ({ isAuthenticated, userRole, handleLogout }) => {
    const navigate = useNavigate();
    const [hoveredMenu, setHoveredMenu] = useState(null);

    return (
        <nav style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            padding: '20px 5%', 
            background: '#0c0a09', 
            borderBottom: '1px solid #262626'
        }}>
            <div onClick={() => navigate('/')} style={{ cursor: 'pointer' }}>
                <h3 style={{ color: '#fef3c7' }}>PasukanYerusSolo</h3>
            </div>

            <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
                {/* Menu Khusus HRD */}
                {isAuthenticated && userRole === 'hrd' && (
                    <>
                        <button onClick={() => navigate('/hrd/dashboard')} style={{ background: 'none', border: 'none', color: '#fff', cursor: 'pointer' }}>Dashboard HRD</button>
                    </>
                )}

                {isAuthenticated ? (
                    <button 
                        onClick={handleLogout}
                        style={{ 
                            background: 'transparent', border: '1px solid #ef4444',
                            color: '#ef4444', padding: '6px 16px', borderRadius: '20px',
                            cursor: 'pointer', fontWeight: '700', fontSize: '12px'
                        }}
                    >Keluar</button>
                ) : (
                    <button 
                        onClick={() => navigate('/login')} 
                        style={{ 
                            padding: '6px 16px', borderRadius: '20px', 
                            border: '1px solid #ea580c', background: 'transparent', 
                            color: '#ea580c', fontWeight: '700', fontSize: '12px', cursor: 'pointer' 
                        }}
                    >Login</button>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
